import{c as a,Q as e,j as i,m as n}from"./chunks/framework.D9IbVcwA.js";const k=JSON.parse('{"title":"000-env-toolchain-1 · 环境搭建","description":"","frontmatter":{"title":"000-env-toolchain-1 · 环境搭建"},"headers":[],"relativePath":"tutorial/000-env-toolchain-1.md","filePath":"tutorial/000-env-toolchain-1.md","lastUpdated":1779686691000}'),l={name:"tutorial/000-env-toolchain-1.md"};function t(p,s,c,o,r,d){return e(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="从零搭建-x86-64-os-开发环境-上-——-工具链与构建系统" tabindex="-1">从零搭建 x86_64 OS 开发环境（上）—— 工具链与构建系统 <a class="header-anchor" href="#从零搭建-x86-64-os-开发环境-上-——-工具链与构建系统" aria-label="Permalink to &quot;从零搭建 x86_64 OS 开发环境（上）—— 工具链与构建系统&quot;">​</a></h1><blockquote><p>标签：OS开发, CMake, 裸机编译, QEMU, 工具链 前置：熟悉 Linux 命令行，有基本的 C/C++ 经验</p></blockquote><h2 id="前言-为什么环境搭建能劝退一半的人" tabindex="-1">前言：为什么环境搭建能劝退一半的人 <a class="header-anchor" href="#前言-为什么环境搭建能劝退一半的人" aria-label="Permalink to &quot;前言：为什么环境搭建能劝退一半的人&quot;">​</a></h2><p>如果你跟我一样， 第一次决定&quot;我要自己写一个操作系统&quot;的时候， 大概率是在某个深夜被一篇 OS 开发教程给戳中了。 然后你兴冲冲地打开终端准备大干一场， 第一步就卡住了——教程说&quot;请先编译一个交叉编译器&quot;， 然后丢给你一个 2006 年的 gcc 源码链接， 让你 <code>make</code> 两个小时。 等你真的把交叉编译器编出来（或者没编出来放弃了）， 写了两行代码编译的时候发现链接报错、 QEMU 黑屏、教程用的 NASM 而你想用 GAS， 整套流程下来你已经不想写 OS 了，你想把电脑砸了。</p><p>这就是为什么 Cinux 的第一个 tag 什么都不做，专门用来搭环境。 我们要做的事情听起来很无聊 ——装几个包、写个检查脚本、配一下 CMake、 编译一个只会在屏幕上显示字母 &quot;C&quot; 然后停机的 512 字节程序。 但这一步解决了后续所有 tag 都会依赖的构建基础设施： 从源码到可启动磁盘镜像的完整流水线。 现在把它搭好、搞懂每一行配置的含义， 后面写 bootloader、内核、驱动的时候就不会再因为编译问题卡住了。</p><h2 id="我们的环境" tabindex="-1">我们的环境 <a class="header-anchor" href="#我们的环境" aria-label="Permalink to &quot;我们的环境&quot;">​</a></h2><p>实验环境是一台 x86_64 Linux 机器 （Ubuntu 22.04 或更新版本）， 工具链完全来自系统包管理器 ——不需要编译交叉编译器，不需要 Docker， 不需要任何特殊准备。 GCC 版本要求 11+（支持 C++23 的基本特性）， CMake 笔者使用的是 4.1（实际 3.20 以上即可）， QEMU 要求 8.0+（模拟 x86_64 启动）。 编辑器随意，但如果用 VS Code 的话， 项目里已经配好了 <code>.clangd</code> 文件， 装上 clangd 插件就能获得代码补全和错误提示。</p><p>这里有一个值得展开说说的选择：为什么不用交叉编译器？ OSDev Wiki 上的 Bare Bones 教程强烈建议你构建一个 <code>x86_64-elf-gcc</code> 交叉编译器， 理由是系统 GCC 可能会隐式链接宿主系统的库、 假设宿主系统的 ABI、 甚至生成一些在裸机上无法运行的代码。 这些担忧在理论上是成立的，但在实际操作中， 只要你加上 <code>-ffreestanding -nostdlib -static</code> 这些 flag， 系统 GCC 生成的代码在 x86_64 裸机上就是完全可用的 ——因为我们的宿主机本身就是 x86_64， 指令集层面没有任何差异。 真正的交叉编译场景 （比如在 x86_64 宿主上编译 ARM 内核） 确实需要专用工具链， 但 x86_64 到 x86_64 这种&quot;伪交叉编译&quot;， 系统 GCC 完全胜任。</p><p>对比一下其他项目的做法： xv6 用的是最暴力的方案 ——Makefile 里直接 <code>CC = $(TOOLPREFIX)gcc</code>， flag 硬编码在 <code>CFLAGS</code> 里， 没有任何 toolchain file 的概念。 这种做法在小项目里完全够用， 但当源文件从 5 个增长到 50 个的时候， Makefile 就开始变成意大利面条了。 SerenityOS 则走另一个极端， 它的 <code>Meta/CMake/</code> 目录下有 30 多个 CMake 模块， 支持多编译器（GCC/Clang）、多架构（x86_64/AArch64/RISC-V）、 代码生成器、IPC IDL 编译器等，复杂度堪比一个中型框架。 Cinux 选择了一条中间路线： 用 CMake 和 toolchain file 管理， 但保持最小化的配置——刚好够用，不多不少。</p><h2 id="第一步——安装工具链并验证" tabindex="-1">第一步——安装工具链并验证 <a class="header-anchor" href="#第一步——安装工具链并验证" aria-label="Permalink to &quot;第一步——安装工具链并验证&quot;">​</a></h2><p>首先把需要的包装上：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gcc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> g++</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> binutils</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qemu-system-x86</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cmake</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gcc-multilib</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> g++-multilib</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>gcc-multilib</code> 和 <code>g++-multilib</code> 这两个包非常容易遗漏， 但它们是必须的——Cinux 的 MBR 和 stage2 bootloader 需要 32 位 ELF 链接（<code>-Wl,-m,elf_i386</code>）， 即使最终的 64 位内核不需要。 如果你漏装了 multilib 包， 链接 bootloader 的时候会收到一个诡异的 <code>cannot find -lgcc_s</code> 错误， 而且报错信息完全不指向真正的原因， 这个坑真的坑了笔者半天。</p><p>装完之后跑一下检查脚本确认：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./scripts/check_toolchain.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>你应该看到每个工具后面都跟着绿色的 <code>[OK]</code>， 最后一行是 <code>[OK] All required tools are installed!</code>。 如果任何一个工具缺失，脚本会直接退出并告诉你安装命令。</p><h2 id="第二步——配-cmake-构建系统" tabindex="-1">第二步——配 CMake 构建系统 <a class="header-anchor" href="#第二步——配-cmake-构建系统" aria-label="Permalink to &quot;第二步——配 CMake 构建系统&quot;">​</a></h2><p>接下来我们要配 CMake， 这是整个项目的构建骨架。 核心文件有三个： 顶层 <code>CMakeLists.txt</code>、 <code>cmake/toolchain-x86_64.cmake</code>、 和 <code>cmake/qemu.cmake</code>。 我们从 toolchain file 开始看， 因为它是整个编译配置的灵魂。</p><div class="language-makefile vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">makefile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">set(CMAKE_SYSTEM_NAME Generic)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">set(CMAKE_SYSTEM_PROCESSOR x86_64)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">set(CMAKE_C_FLAGS_INIT &quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    -ffreestanding</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    -fno-stack-protector</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    -mno-red-zone</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    -mcmodel=kernel</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    -Wall</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    -Wextra</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">set(CMAKE_CXX_FLAGS_INIT </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">\${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CMAKE_C_FLAGS_INIT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    -fno-exceptions</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    -fno-rtti</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    -std=c++23</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">set(CMAKE_EXE_LINKER_FLAGS_INIT &quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    -nostdlib</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    -static</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    -Wl,--build-id=none</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br></div></div><p><code>CMAKE_SYSTEM_NAME Generic</code> 是这整个文件最重要的一个设置 ——它告诉 CMake &quot;目标平台没有操作系统&quot;。 这个值会触发 CMake 的一系列行为变化： 禁用 <code>find_package</code> 的默认搜索 （因为没有系统库可找）， 不允许 <code>try_run</code> （因为编译产物不能在宿主上运行），等等。 笔者有一次手滑把这个写成了 <code>Linux</code>， 结果后面所有的编译都正常通过， 但链接出来的内核一跑就 triple fault ——因为 CMake 按照 Linux 程序的方式 注入了一堆不该有的链接 flag。 排查了整整两个小时才发现是这一个词的问题， 那种感觉真的让人血压拉满。</p><p>编译 flag 的含义我们逐个过一遍。 <code>-ffreestanding</code> 告诉 GCC 代码运行在没有操作系统的裸机环境， 只提供 freestanding 头文件 （<code>&lt;stdint.h&gt;</code>, <code>&lt;stddef.h&gt;</code>, <code>&lt;stdarg.h&gt;</code> 等）， 不提供 <code>printf</code>、<code>malloc</code> 这些。 <code>-fno-stack-protector</code> 禁用栈保护， 因为栈保护的 canary 初始化依赖 <code>__stack_chk_fail</code> 函数， 这个函数需要标准库提供，内核里什么都没有。 <code>-mno-red-zone</code> 禁用 x86_64 System V ABI 里的 red zone ——这是给用户态程序的一个 128 字节栈下空间优化， 允许函数在不调整 RSP 的情况下使用栈空间。 但在内核里，中断可能在任何时候打断执行 （包括红区里的代码）， 如果用了红区，中断处理程序的栈帧会覆盖掉还没用完的数据， 直接导致数据损坏和难以调试的随机崩溃。 <code>-mcmodel=kernel</code> 告诉编译器代码会运行在地址空间最顶端 （高半核，约 <code>0xFFFFFFFF80000000</code>）， 这影响了它生成绝对地址引用的方式。</p><p>C++ 特有的 flag 禁用了异常和 RTTI。 为什么 OS 内核不能用异常？ 原因在于异常的展开（unwinding）需要 <code>.eh_frame</code> 段 和 <code>__cxa_begin_catch</code>、<code>__cxa_end_catch</code> 等运行时函数的支持， 这些都需要标准库提供。 而且异常展开会隐式调用析构函数， 这要求堆分配器已经初始化 ——但堆分配器本身就是内核的一部分，形成了循环依赖。 SerenityOS 的做法更有趣： 它允许异常，但自己实现了全套异常运行时（<code>__cxa_*</code> 函数）， 代价是显著的复杂度。 对于教学项目来说，直接禁用异常用返回值替代是更简洁的选择。</p><p><code>CMAKE_*_FLAGS_INIT</code> 和直接设 <code>CMAKE_*_FLAGS</code> 的区别值得说一句。 <code>_INIT</code> 变量只在第一次 configure 时被读取， 之后用户可以通过命令行追加自定义 flag 而不会和 toolchain file 的 flag 冲突； 直接设 <code>CMAKE_C_FLAGS</code> 则会阻止用户的 flag 生效。 所以 toolchain file 里必须用 <code>_INIT</code> 版本， 这是 CMake 官方推荐的做法。</p><p>到这里构建系统的骨架就搭好了。 在项目根目录执行 configure：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -DCMAKE_BUILD_TYPE=Debug</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ..</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>终端会打印构建配置摘要， 确认 CXX Compiler 显示的是系统 GCC 路径， Toolchain 显示的是项目里的 toolchain file。</p><p>下一篇我们将在这个基础上编写第一个 MBR 存根， 把从汇编源码到 QEMU 启动的完整构建链条跑通。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li>Intel SDM — <a href="https://www.intel.com/content/www/us/en/developer/articles/technical/intel-sdm.html" target="_blank" rel="noreferrer">Volume 1</a>: Chapter 3 Basic Execution Environment， 描述实模式寄存器和 red zone 约束</li><li>OSDev Wiki — <a href="https://wiki.osdev.org/Bare_Bones" target="_blank" rel="noreferrer">Bare Bones</a>: 交叉编译器和 freestanding 编译 flag 的权威参考</li><li>CMake 官方 — <a href="https://cmake.org/cmake/help/latest/manual/cmake-toolchains.7.html" target="_blank" rel="noreferrer">cmake-toolchains(7)</a>: toolchain file 完整文档</li><li>xv6 — <a href="https://github.com/mit-pdos/xv6-riscv" target="_blank" rel="noreferrer">mit-pdos/xv6-riscv</a>: 极简 Makefile 构建方案</li><li>SerenityOS — <a href="https://github.com/SerenityOS/serenity" target="_blank" rel="noreferrer">SerenityOS/serenity</a>: 生产级 OS 的 CMake 架构</li></ul>`,29)])])}const E=a(l,[["render",t]]);export{k as __pageData,E as default};
